local LTreasureObjCtrl = LxClass("LTreasureObjCtrl",nil)
-----------------------------------------------------------------
local LFightBaseObj = LXImport("..View.LFightBaseObj")

LTreasureObjCtrl.BORN_OFFSET = 6


function LTreasureObjCtrl:LTreasureObjCtrl(battleUnit)
    self._battleUnit = battleUnit
    self._objMap = {}
    self._used = {}
end

function LTreasureObjCtrl:LoadObj(heroId,effData,endFunc)
    local heroEffId = tonumber(effData.effRes)
    local key = string.format("%s_%s",heroId,heroEffId)
    local obj = self._objMap[key]
    if obj then
        return obj
    end

    obj = LFightBaseObj:New()
    local effTrans = self._battleUnit:GetEffectRootTrans()
    self._scale = tonumber(effData.playNum)

    local data =
    {
        battleUnit = self._battleUnit,
        heroEffId = heroEffId,
        scale = self._scale,
        side =LFightConst.ACTON_TEAM_A,
        pos = Vector3(-10,0,0),
        layerName = "ObjectUp",
        parentTran = effTrans,
        onComplete = function()
            if endFunc then
                endFunc()
            end
        end,

    }
    obj:Create(data)



    self._objMap[key] = obj
    return obj
end

