function LTreasureObjCtrl:ClearAllObj()
    if self._objMap then
        for k,v in pairs(self._objMap) do
            v:Destroy()
        end
    end
    self._objMap = {}
end

function LTreasureObjCtrl:Destroy()
    self:ClearAllObj()
    table.removeall(self)
end


return LTreasureObjCtrl